import React from "react";
import Pagination from "~/common/components/major/Pagination";
import { View } from "react-native";
import ImageFeed from "~/common/components/major/ImageFeed";
import { actionData, initialData, reducerData } from "~/utils/reducers/data";
import { readImagesAsync } from "~/utils/api/firebase";
import useStorage from "~/utils/hooks/useStorage";
import { shuffleArray } from "~/utils/api/data";

export default function Images() {
  const [state, dispatch] = React.useReducer(reducerData, initialData);
  const { getItem, setItem } = useStorage("@images");

  const getImages = React.useCallback(() => {
    const item = getItem();

    if (item) {
      console.log("got from local");
      return dispatch(actionData.setData(shuffleArray(item)));
    }

    downloadData();
  }, []);

  const downloadData = React.useCallback(async () => {
    const data = await readImagesAsync();
    dispatch(actionData.setData(data));
    setItem(data);
  }, []);

  React.useEffect(() => {
    getImages();
  }, []);

  const setIndex = React.useCallback((id) => {
    dispatch(actionData.setCurrentPage(id));
  }, []);

  return (
    <View style={{ flex: 1 }}>
      <ImageFeed
        currentRoute={"Image"}
        currentIndex={state.currentPage}
        data={state.currentPageData}
        ListHeaderComponent={
          <Pagination
            currentPage={state.currentPage}
            onPageChange={setIndex}
            pageCount={5}
            pageSize={20}
            dataLength={state.data.length}
          />
        }
      />
    </View>
  );
}
